// Input-Validierung und Vorbereitung
const body = $input.item.json.body;

if (!body.topic || !body.studentId) {
  throw new Error('Fehlende Parameter: topic und studentId erforderlich');
}

const topic = body.topic;
const difficulty = body.difficulty || 'mittel';
const studentId = body.studentId;
const includeTestCases = body.includeTestCases !== false;

// Prompt für AI vorbereiten
const systemPrompt = `Du bist ein erfahrener C# Dozent und Softwareentwickler. 
Deine Aufgabe ist es, präzise und lehrreiche Programmieraufgaben für Studenten zu erstellen.
Die Aufgaben sollen praxisnah sein und Best Practices vermitteln.`;

const userPrompt = `Erstelle eine C# Programmieraufgabe zum Thema: "${topic}"

Schwierigkeitsgrad: ${difficulty}

Die Aufgabe soll folgende Struktur haben:
1. Titel (kurz und prägnant)
2. Beschreibung (Was soll programmiert werden?)
3. Anforderungen (Liste mit mindestens 5 konkreten Anforderungen)
4. ${includeTestCases ? 'Testfälle (mindestens 3 Beispiel-Inputs mit erwarteten Outputs)' : ''}
5. Hinweise (optionale Tipps für die Umsetzung)
6. Lernziele (Was lernt der Student?)

Format: JSON mit dieser Struktur:
{
  "title": "...",
  "description": "...",
  "requirements": ["..."],
  "testCases": [{"input": "...", "expectedOutput": "..."}],
  "hints": ["..."],
  "learningGoals": ["..."]
}`;

return {
  json: {
    studentId,
    topic,
    difficulty,
    systemPrompt,
    userPrompt,
    timestamp: new Date().toISOString()
  }
};

// AI Response verarbeiten und strukturieren
const aiResponse = $input.item.json.choices[0].message.content;
const taskData = JSON.parse(aiResponse);
const studentId = $('Request Validierung').item.json.studentId;
const topic = $('Request Validierung').item.json.topic;
const difficulty = $('Request Validierung').item.json.difficulty;

// Vollständige Aufgaben-Struktur
const task = {
  id: `task-${Date.now()}`,
  studentId: studentId,
  topic: topic,
  difficulty: difficulty,
  title: taskData.title,
  description: taskData.description,
  requirements: taskData.requirements,
  testCases: taskData.testCases || [],
  hints: taskData.hints || [],
  learningGoals: taskData.learningGoals || [],
  createdAt: new Date().toISOString(),
  status: 'open'
};

return {
  json: task
};

// Error Handling
const error = $input.item.json.error;

return {
  json: {
    success: false,
    error: error?.message || 'Unbekannter Fehler',
    timestamp: new Date().toISOString()
  }
};
